// Compute current month info for file paths and prompts
const now = new Date();
const year = now.getFullYear().toString();
const month = String(now.getMonth() + 1).padStart(2, '0');
const monthName = now.toLocaleString('en-US', { month: 'long' });
// Send date: 3rd of the month
const sendDate = `${year}-${month}-03`;

return {
  json: {
    year,
    month,
    monthName,
    monthYear: `${monthName} ${year}`,
    sendDate,
    obsidianPath: `StPeteMusic/newsletters/${year}/${month}-newsletter.md`,
    newsletterTitle: `St Pete Music Newsletter - ${monthName} ${year}`
  }
};

// Combine PostSchedule + IG_PastPosts + featured blurbs into a single structured prompt context.

const monthCtx = $('Get Month Info').first().json;
const scheduleRows = $('Read PostSchedule').all().map(i => i.json);
const igRows = $('Read IG_PastPosts').all().map(i => i.json);

// Try to get pre-approved featured artist blurbs — graceful fallback if endpoint is down
let preApprovedBlurbs = [];
try {
  const blurbsData = $('Fetch Featured Blurbs').first().json;
  if (Array.isArray(blurbsData)) {
    preApprovedBlurbs = blurbsData;
  }
} catch (e) {
  // Blurbs unavailable — Claude will write the Featured Bands section from scratch
}

console.log('[newsletter] pre-approved blurbs found:', preApprovedBlurbs.length);

const scheduleText = scheduleRows.length > 0
  ? scheduleRows
      .map(r => Object.entries(r).map(([k, v]) => `${k}: ${v}`).join(' | '))
      .join('\n')
  : 'No upcoming events data available.';

const igText = igRows.length > 0
  ? igRows
      .slice(-10)
      .map(r => Object.entries(r).map(([k, v]) => `${k}: ${v}`).join(' | '))
      .join('\n')
  : 'No recent IG post data available.';

const blurbsSection = preApprovedBlurbs.length > 0
  ? '\n\nPRE-APPROVED FEATURED ARTIST BLURBS — insert these verbatim into the Featured Bands section, in order:\n'
    + preApprovedBlurbs
        .sort((a, b) => a.order_position - b.order_position)
        .map(b => '[Position ' + b.order_position + '] ' + b.artist_name
          + (b.artist_instagram_handle ? ' (@' + b.artist_instagram_handle + ')' : '')
          + ':\n' + b.newsletter_blurb)
        .join('\n\n')
  : '';

const featuredBandsInstruction = preApprovedBlurbs.length > 0
  ? 'For the Featured Bands section, use ONLY the PRE-APPROVED BLURBS above — insert them verbatim, do not rewrite or summarize.'
  : 'For the Featured Bands section, spotlight 1-2 bands from the events data.';

const prompt = `You are drafting the monthly newsletter for StPeteMusic for ${monthCtx.monthYear}.

Here is the upcoming event/post schedule data (PostSchedule sheet):
${scheduleText}

Here are recent Instagram post records for the Social Roundup section (IG_PastPosts sheet):
${igText}${blurbsSection}

Using the data above, write the full newsletter body HTML following your style guidelines.
Focus on Suite E Studios events. ${featuredBandsInstruction}
For the Social Roundup, pick 2-3 of the most recent IG/YouTube posts.
Remember: output ONLY the four-section HTML body. No extra text or markdown fences.`;

return {
  json: {
    ...monthCtx,
    prompt
  }
};
